def solution():
    # Define variables for tax calculation
    tax_liability = 12000    # Initial tax liability in dollars
    tax_credit = 3500        # Nonrefundable tax credit in dollars
    refundable = False       # Indicates the tax credit is nonrefundable

    # Calculate remaining tax liability after applying the credit
    if refundable:
        remaining_liability = tax_liability - tax_credit
    else:
        remaining_liability = max(0, tax_liability - tax_credit)

    # Return the final tax liability rounded to the nearest integer
    return round(remaining_liability)
